export const LANDING_FAQ = [
  {
    question: "How can I create a sell or buyback request?",
    answer:
      "Simply register, submit your item details and photos, and our team will review your request and send you a valuation offer within 24 hours.",
  },
  {
    question: "How is the price of my item determined?",
    answer:
      "Our pricing combines AI-driven market analysis with expert human appraisal to ensure you receive a fair, accurate, and competitive offer.",
  },
  {
    question: "How is my item authenticated?",
    answer:
      "Every item undergoes a rigorous multi-step authentication process using advanced tools like Entrupy alongside certified human experts to verify authenticity, condition, and value.",
  },
  {
    question: "Is it secure to send my item via courier?",
    answer:
      "Yes. We partner with Brink's to provide fully insured, tracked, and secure pickup and delivery for all items handled through LuxFlow.",
  },
  {
    question: "Why there are fees associated with the offer?",
    answer:
      "Our fees cover the full end-to-end service: authentication, secure storage, insurance, logistics, and same-day payout processing.",
  },
  {
    question: "How long does it take to receive the funds from the offer?",
    answer:
      "Once your item passes authentication and you accept the offer, funds are typically disbursed the same day via bank transfer, PayPal, or stablecoins.",
  },
];

